import React, { useEffect, useState } from 'react';
import { fetchPlans, createPlan, deletePlan } from './api';

function App() {
  const [plans, setPlans] = useState([]);
  const [examType, setExamType] = useState('');
  const [topics, setTopics] = useState('');
  const [studyTime, setStudyTime] = useState('');

  // Sayfa açıldığında verileri getir
  useEffect(() => {
    getPlans();
  }, []);

  const getPlans = async () => {
    try {
      const { data } = await fetchPlans();
      setPlans(data);
    } catch (err) {
      console.error("Veri çekme hatası:", err);
    }
  };

  const handleAddPlan = async (e) => {
    e.preventDefault();
    if (!examType || !topics) return;

    const newPlan = {
      examType,
      topics: topics.split(',').map(t => t.trim()),
      studyTime: Number(studyTime) || 1
    };

    try {
      await createPlan(newPlan);
      setExamType(''); setTopics(''); setStudyTime(''); // Formu temizle
      getPlans(); // Listeyi tazele
    } catch (err) {
      alert("Plan kaydedilirken bir hata oluştu.");
    }
  };

  const handleDelete = async (id) => {
    await deletePlan(id);
    getPlans();
  };

  return (
    <div className="min-h-screen bg-butterYellow p-6 font-sans text-gray-700">
      <div className="max-w-3xl mx-auto">
        {/* Header */}
        <header className="text-center mb-10">
          <h1 className="text-5xl font-bold text-softPink mb-2">Planly 🌸</h1>
          <p className="text-gray-500 italic">Sınav yolculuğunda seninle.</p>
        </header>

        {/* Form Kartı */}
        <div className="bg-white rounded-3xl shadow-lg p-8 mb-10 border border-softBeige">
          <form onSubmit={handleAddPlan} className="grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
            <div className="md:col-span-1">
              <label className="block text-xs font-bold mb-1 ml-1 text-gray-400">SINAV</label>
              <input value={examType} onChange={(e)=>setExamType(e.target.value)} placeholder="Örn: KPSS" className="w-full p-3 rounded-xl bg-gray-50 border-none focus:ring-2 focus:ring-softPink outline-none" />
            </div>
            <div className="md:col-span-1">
              <label className="block text-xs font-bold mb-1 ml-1 text-gray-400">KONULAR</label>
              <input value={topics} onChange={(e)=>setTopics(e.target.value)} placeholder="Matematik, Tarih..." className="w-full p-3 rounded-xl bg-gray-50 border-none focus:ring-2 focus:ring-softPink outline-none" />
            </div>
            <div className="md:col-span-1">
              <label className="block text-xs font-bold mb-1 ml-1 text-gray-400">SAAT</label>
              <input type="number" value={studyTime} onChange={(e)=>setStudyTime(e.target.value)} placeholder="4" className="w-full p-3 rounded-xl bg-gray-50 border-none focus:ring-2 focus:ring-softPink outline-none" />
            </div>
            <button type="submit" className="bg-softPink text-white font-bold py-3 rounded-xl hover:bg-[#f4978e] transition-all shadow-md">Ekle ✨</button>
          </form>
        </div>

        {/* Plan Listesi */}
        <div className="grid gap-6">
          {plans.map((plan) => (
            <div key={plan._id} className="bg-white p-6 rounded-2xl shadow-sm border-l-8 border-softGreen flex justify-between items-center group hover:shadow-md transition-all">
              <div>
                <h3 className="text-xl font-bold text-gray-600">{plan.examType}</h3>
                <div className="flex flex-wrap gap-2 mt-2">
                  {plan.topics.map((t, i) => (
                    <span key={i} className="text-xs bg-softPink/10 text-softPink px-2 py-1 rounded-md">{t}</span>
                  ))}
                </div>
              </div>
              <div className="text-right flex items-center gap-4">
                <span className="text-sm font-bold bg-softBeige text-gray-500 px-3 py-1 rounded-full">{plan.studyTime} Saat</span>
                <button onClick={() => handleDelete(plan._id)} className="text-gray-300 hover:text-red-400 transition-colors">🗑️</button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

export default App;
